use std::collections::BTreeMap;

pub fn summarize_sales(input: &str) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for line in input.lines() {
        let mut parts = line.split(',');
        let day = parts.next().unwrap_or("");
        let category = parts.next().unwrap_or("");
        let amount = parts.next().unwrap_or("");

        if !day.is_empty() && !category.is_empty() {
            if let Ok(value) = amount.parse::<i32>() {
                if value > 0 {
                    *totals.entry(category).or_insert(0) += value;
                }
            }
        }
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(b.0)));

    let mut out = String::from("category,total\n");
    for (category, total) in rows {
        out.push_str(&format!("{},{}\n", category, total));
    }
    out
}

#[cfg(test)]
mod tests {
    use super::summarize_sales;

    #[test]
    fn aggregates_and_sorts_report() {
        let input = "2024-05-01,books,10\n2024-05-01,games,25\n2024-05-02,books,7\n2024-05-03,games,5\n2024-05-03,toys,-3\n2024-05-04,books,bad\n2024-05-05,art,25\n";
        let expected = "category,total\nart,25\ngames,30\nbooks,17\n";
        assert_eq!(summarize_sales(input), expected);
    }

    #[test]
    fn returns_no_data_when_every_row_is_invalid() {
        let input = "2024-05-01,books,0\n,tools,8\n2024-05-02,,4\n2024-05-03,art,-2\n2024-05-04,games,nope\n";
        assert_eq!(summarize_sales(input), "no data");
    }
}

