#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.name.cmp(&b.name))
            .then_with(|| a.penalties.cmp(&b.penalties))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut current_rank = 1;

    for (idx, p) in items.into_iter().enumerate() {
        if idx > 0 {
            let prev = &out[idx - 1];
            if prev.score != p.score || prev.penalties != p.penalties {
                current_rank = idx + 1;
            }
        }

        out.push(RankedPlayer {
            rank: current_rank,
            name: p.name,
            score: p.score,
            penalties: p.penalties,
        });
    }

    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &str, score: u32, penalties: u32) -> Player {
        Player {
            name: name.to_string(),
            score,
            penalties,
        }
    }

    #[test]
    fn sorts_by_score_then_penalties_then_name() {
        let ranked = rank_players(&[
            p("Zoe", 15, 1),
            p("Amy", 15, 0),
            p("Bob", 15, 0),
            p("Cara", 12, 2),
        ]);

        let names: Vec<_> = ranked.into_iter().map(|r| r.name).collect();
        assert_eq!(names, vec!["Amy", "Bob", "Zoe", "Cara"]);
    }

    #[test]
    fn equal_score_and_penalties_share_rank() {
        let ranked = rank_players(&[
            p("Bob", 20, 1),
            p("Amy", 20, 1),
            p("Cara", 18, 0),
            p("Dan", 18, 2),
        ]);

        let pairs: Vec<_> = ranked.into_iter().map(|r| (r.name, r.rank)).collect();
        assert_eq!(pairs, vec![
            ("Amy".to_string(), 1),
            ("Bob".to_string(), 1),
            ("Cara".to_string(), 3),
            ("Dan".to_string(), 4),
        ]);
    }

    #[test]
    fn lower_penalties_beat_alphabetical_order() {
        let ranked = rank_players(&[
            p("Aaron", 30, 3),
            p("Zed", 30, 1),
            p("Mia", 30, 2),
        ]);

        let names: Vec<_> = ranked.into_iter().map(|r| r.name).collect();
        assert_eq!(names, vec!["Zed", "Mia", "Aaron"]);
    }
}

