use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    Todo,
    InProgress,
    Blocked,
    Done,
    Rejected,
}

impl State {
    fn as_str(self) -> &'static str {
        match self {
            State::Todo => "Todo",
            State::InProgress => "InProgress",
            State::Blocked => "Blocked",
            State::Done => "Done",
            State::Rejected => "Rejected",
        }
    }
}

enum Event {
    Start,
    Block,
    Unblock,
    Finish,
    Reopen,
    Reject,
}

struct Ticket {
    state: State,
    blockers: u32,
}

impl Ticket {
    fn new() -> Self {
        Self {
            state: State::Todo,
            blockers: 0,
        }
    }

    fn apply(&mut self, event: Event) {
        match event {
            Event::Start => {
                if self.state == State::Todo {
                    self.state = State::InProgress;
                }
            }
            Event::Block => {
                self.blockers += 1;
                self.state = State::Blocked;
            }
            Event::Unblock => {
                if self.blockers > 0 {
                    self.blockers -= 1;
                }
                self.state = State::Todo;
            }
            Event::Finish => {
                if self.state != State::Rejected {
                    self.state = State::Done;
                }
            }
            Event::Reopen => {
                self.state = State::Todo;
            }
            Event::Reject => {
                self.state = State::Rejected;
            }
        }
    }
}

fn main() {
    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    tickets.insert("T1", Ticket::new());
    tickets.insert("T2", Ticket::new());
    tickets.insert("T3", Ticket::new());

    let log = vec![
        ("T1", Event::Start),
        ("T1", Event::Block),
        ("T1", Event::Unblock),
        ("T1", Event::Block),
        ("T1", Event::Reject),
        ("T2", Event::Start),
        ("T2", Event::Finish),
        ("T2", Event::Reopen),
        ("T2", Event::Start),
        ("T2", Event::Finish),
        ("T3", Event::Start),
        ("T3", Event::Block),
        ("T3", Event::Unblock),
    ];

    for (id, event) in log {
        tickets.get_mut(id).unwrap().apply(event);
    }

    let mut lines = Vec::new();
    for (id, ticket) in tickets {
        lines.push(format!("{}:{}:{}", id, ticket.state.as_str(), ticket.blockers));
    }
    println!("{}", lines.join("\n"));
}

