#[derive(Clone, Copy)]
struct Booking {
    room: &'static str,
    start: u32,
    end: u32,
}

fn can_book(existing: &[Booking], room: &str, start: u32, end: u32, capacity: usize) -> bool {
    if start >= end {
        return false;
    }

    let overlaps = existing
        .iter()
        .filter(|b| b.room == room)
        .filter(|b| !(end < b.start || start > b.end))
        .count();

    overlaps < capacity
}

fn main() {
    let existing = [
        Booking { room: "A", start: 10, end: 20 },
        Booking { room: "A", start: 15, end: 25 },
        Booking { room: "A", start: 25, end: 30 },
        Booking { room: "B", start: 10, end: 12 },
    ];

    let checks = [
        ("A", 20, 25, 2, "A"),
        ("A", 15, 15, 1, "B"),
        ("A", 18, 14, 3, "C"),
        ("B", 12, 14, 1, "D"),
        ("A", 24, 25, 2, "E"),
        ("A", 24, 26, 2, "F"),
        ("C", 0, 100, 1, "G"),
    ];

    for (room, start, end, capacity, label) in checks {
        println!("{} {}", label, can_book(&existing, room, start, end, capacity));
    }
}

