use std::cmp::Reverse;

#[derive(Clone, Debug)]
struct Player {
    name: &'static str,
    score: u32,
    wins: u32,
}

fn ranked_lines(mut players: Vec<Player>) -> Vec<String> {
    players.sort_by_key(|p| (Reverse(p.score), p.name, Reverse(p.wins)));

    let mut lines = Vec::new();
    let mut rank = 1usize;

    for (i, p) in players.iter().enumerate() {
        if i > 0 {
            let prev = &players[i - 1];
            if prev.score != p.score || prev.wins != p.wins {
                rank = i + 1;
            }
        }
        lines.push(format!("{}. {} (score={}, wins={})", rank, p.name, p.score, p.wins));
    }

    lines
}

fn main() {
    let players = vec![
        Player { name: "amy", score: 12, wins: 3 },
        Player { name: "bob", score: 12, wins: 4 },
        Player { name: "cara", score: 9, wins: 5 },
        Player { name: "dave", score: 12, wins: 4 },
        Player { name: "eve", score: 9, wins: 5 },
    ];

    println!("{}", ranked_lines(players).join("\n"));
}

use std::collections::BTreeMap;

struct Order {
    region: &'static str,
    amount: i32,
    refunded: bool,
}

#[derive(Default)]
struct Summary {
    orders: usize,
    gross: i32,
    refunded: i32,
    net: i32,
}

fn main() {
    let orders = [
        Order { region: "North", amount: 120, refunded: false },
        Order { region: "South", amount: 80, refunded: false },
        Order { region: "North", amount: 50, refunded: true },
        Order { region: "West", amount: 40, refunded: false },
        Order { region: "South", amount: 120, refunded: true },
        Order { region: "North", amount: 130, refunded: false },
        Order { region: "West", amount: 60, refunded: false },
    ];

    let mut per_region: BTreeMap<&str, Summary> = BTreeMap::new();

    for order in orders {
        let entry = per_region.entry(order.region).or_default();
        if order.refunded {
            entry.refunded += order.amount;
        } else {
            entry.orders += 1;
            entry.gross += order.amount;
            entry.net += order.amount;
        }
    }

    let mut total_orders = 0usize;
    let mut total_net = 0i32;
    let mut top_region = "";
    let mut top_net = i32::MIN;

    for (region, summary) in &per_region {
        total_orders += summary.orders;
        total_net += summary.net;
        if summary.net > top_net {
            top_net = summary.net;
            top_region = region;
        }
        println!(
            "{}: orders={} gross={} refunded={} net={}",
            region, summary.orders, summary.gross, summary.refunded, summary.net
        );
    }

    println!("TOTAL orders={} net={}", total_orders, total_net);
    println!("TOP {} {}", top_region, top_net);
}

