use std::collections::BTreeMap;

#[derive(Clone, Debug)]
enum State {
    New,
    InProgress,
    OnHold,
    Closed(&'static str),
}

#[derive(Clone, Debug)]
enum Event {
    Start,
    Hold,
    Resume,
    Resolve,
    Cancel,
    Reopen,
}

fn apply_event(state: State, event: &Event) -> State {
    match (state, event) {
        (State::New, Event::Start) => State::InProgress,
        (State::InProgress, Event::Hold) => State::OnHold,
        (State::OnHold, Event::Resume) => State::InProgress,
        (State::InProgress, Event::Resolve) => State::Closed("resolved"),
        (State::OnHold, Event::Resolve) => State::Closed("resolved"),
        (State::New, Event::Cancel) => State::Closed("cancelled"),
        (State::InProgress, Event::Cancel) => State::Closed("cancelled"),
        (State::OnHold, Event::Cancel) => State::Closed("cancelled"),
        (State::Closed(_), Event::Reopen) => State::New,
        (s, _) => s,
    }
}

fn state_str(state: &State) -> String {
    match state {
        State::New => "New".to_string(),
        State::InProgress => "InProgress".to_string(),
        State::OnHold => "OnHold".to_string(),
        State::Closed(reason) => format!("Closed({reason})"),
    }
}

fn main() {
    let data = [
        ("A", vec![Event::Start, Event::Hold, Event::Resume, Event::Resolve, Event::Reopen, Event::Start, Event::Resolve]),
        ("B", vec![Event::Start, Event::Hold, Event::Reopen, Event::Start]),
        ("C", vec![Event::Start, Event::Cancel, Event::Reopen, Event::Cancel]),
        ("D", vec![Event::Resolve, Event::Hold, Event::Resume]),
    ];

    let mut out = BTreeMap::new();
    for (id, events) in data {
        let mut state = State::New;
        for ev in &events {
            state = apply_event(state, ev);
        }
        out.insert(id, state_str(&state));
    }

    for (id, state) in out {
        println!("{id}: {state}");
    }
}

