fn apply_event(state: State, event: &Event) -> State {
    match (state, event) {
        (State::New, Event::Start) => State::InProgress,
        (State::InProgress, Event::Hold) => State::OnHold,
        (State::OnHold, Event::Resume) => State::InProgress,
        (State::InProgress, Event::Resolve) | (State::OnHold, Event::Resolve) => {
            State::Closed("resolved")
        }
        (State::New, Event::Cancel)
        | (State::InProgress, Event::Cancel)
        | (State::OnHold, Event::Cancel) => State::Closed("cancelled"),
        (State::Closed("resolved"), Event::Reopen) => State::InProgress,
        (State::Closed("cancelled"), Event::Reopen) => State::New,
        (s, _) => s,
    }
}

