#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Todo,
    InProgress,
    Blocked,
    Done,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Todo, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::InProgress,
        (Status::InProgress, Event::Complete) => Status::Done,
        (Status::Done, Event::Reopen) => Status::Todo,
        (s, _) => s,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn normal_flow_reaches_done() {
        let s = apply_event(Status::Todo, Event::Start);
        let s = apply_event(s, Event::Complete);
        assert_eq!(s, Status::Done);
    }

    #[test]
    fn blocked_task_can_complete_after_unblock() {
        let s = apply_event(Status::Todo, Event::Start);
        let s = apply_event(s, Event::Block);
        let s = apply_event(s, Event::Unblock);
        let s = apply_event(s, Event::Complete);
        assert_eq!(s, Status::Done);
    }

    #[test]
    fn done_task_cannot_be_blocked() {
        let s = apply_event(Status::Done, Event::Block);
        assert_eq!(s, Status::Done);
    }

    #[test]
    fn blocked_task_can_be_reopened_to_todo() {
        let s = apply_event(Status::Blocked, Event::Reopen);
        assert_eq!(s, Status::Todo);
    }
}

