#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
}

pub fn advance(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        _ => status,
    }
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    let mut status = initial;
    for &event in events {
        status = advance(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn blocked_ticket_can_be_resolved_after_unblock() {
        let events = [Event::Start, Event::Block, Event::Unblock, Event::Resolve];
        assert_eq!(apply_events(Status::Open, &events), Status::Resolved);
    }

    #[test]
    fn reopening_a_closed_ticket_goes_back_to_open() {
        let events = [Event::Start, Event::Resolve, Event::Close, Event::Reopen];
        assert_eq!(apply_events(Status::Open, &events), Status::Open);
    }

    #[test]
    fn reopening_then_starting_allows_work_to_resume() {
        let events = [Event::Start, Event::Resolve, Event::Close, Event::Reopen, Event::Start];
        assert_eq!(apply_events(Status::Open, &events), Status::InProgress);
    }

    #[test]
    fn close_without_resolution_is_ignored() {
        let events = [Event::Start, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::InProgress);
    }
}

use std::collections::BTreeMap;

#[derive(Debug, Clone, Copy)]
pub struct Event {
    pub team: &'static str,
    pub points: i32,
    pub penalty: bool,
    pub active: bool,
}

pub fn build_report(events: &[Event]) -> String {
    let mut totals: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for e in events {
        if !e.active {
            continue;
        }
        let entry = totals.entry(e.team).or_insert((0, 0));
        entry.0 += e.points;
        entry.1 += 1;
    }

    let mut rows: Vec<(&str, i32, usize)> = totals
        .into_iter()
        .map(|(team, (points, count))| (team, points, count))
        .collect();

    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (team, points, count) in rows {
        out.push_str(&format!("{}:{}:{}\n", team, points, count));
    }
    out
}

