#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;
    for event in events {
        status = match (status, event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::Open, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::Open,
            (current, _) => current,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn close_requires_resolution_first() {
        assert_eq!(apply_events(&[Close]), Status::Open);
        assert_eq!(apply_events(&[Start, Close]), Status::InProgress);
    }

    #[test]
    fn reopen_from_closed_goes_to_in_progress() {
        assert_eq!(apply_events(&[Start, Resolve, Close, Reopen]), Status::InProgress);
    }

    #[test]
    fn resolve_then_reopen_keeps_history_workflow_alive() {
        assert_eq!(apply_events(&[Resolve, Close, Reopen, Resolve]), Status::Resolved);
    }

    #[test]
    fn reopen_without_close_does_nothing() {
        assert_eq!(apply_events(&[Start, Reopen]), Status::InProgress);
        assert_eq!(apply_events(&[Resolved, Reopen].into_events()), Status::Resolved);
    }

    trait IntoEvents {
        fn into_events(self) -> Vec<super::Event>;
    }

    impl IntoEvents for [Status; 2] {
        fn into_events(self) -> Vec<super::Event> {
            let mut out = Vec::new();
            for s in self {
                match s {
                    Status::Open => {}
                    Status::InProgress => out.push(Start),
                    Status::Resolved => out.push(Resolve),
                    Status::Closed => {
                        out.push(Resolve);
                        out.push(Close);
                    }
                }
            }
            out
        }
    }
}

