fn parse_line(line: &str) -> (String, bool, String) {
    let parts: Vec<&str> = line.split(',').collect();
    let name = parts.get(0).unwrap_or(&"").to_string();
    if parts.len() < 4 {
        return (name, false, "bad field count".to_string());
