use std::collections::BTreeMap;

struct Sale {
    region: &'static str,
    amount: i32,
    refunded: bool,
}

fn main() {
    let sales = vec![
        Sale { region: "north", amount: 10, refunded: false },
        Sale { region: "south", amount: 7, refunded: true },
        Sale { region: "north", amount: 5, refunded: true },
        Sale { region: "south", amount: 6, refunded: false },
    ];

    let mut gross_by_region: BTreeMap<&str, i32> = BTreeMap::new();
    let mut refunds_by_region: BTreeMap<&str, i32> = BTreeMap::new();
    let mut orders_by_region: BTreeMap<&str, i32> = BTreeMap::new();

    for sale in &sales {
        if !sale.refunded {
            *gross_by_region.entry(sale.region).or_insert(0) += sale.amount;
        }
        if sale.refunded {
            *refunds_by_region.entry(sale.region).or_insert(0) += 1;
        }
        *orders_by_region.entry(sale.region).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    let mut total_orders = 0;
    let mut total_gross = 0;
    let mut total_refunds = 0;
    let mut total_net = 0;

    for region in orders_by_region.keys() {
        let orders = *orders_by_region.get(region).unwrap_or(&0);
        let gross = *gross_by_region.get(region).unwrap_or(&0);
        let refunds = *refunds_by_region.get(region).unwrap_or(&0);
        let net = gross - refunds;

        total_orders += orders;
        total_gross += gross;
        total_refunds += refunds;
        total_net += net;

        lines.push(format!(
            "{} orders={} gross={} refunds={} net={}",
            region, orders, gross, refunds, net
        ));
    }

    lines.push(format!(
        "total orders={} gross={} refunds={} net={}",
        total_orders, total_gross, total_refunds, total_net
    ));

