enum Event {
    Open,
    Assign,
    Block,
    Unblock,
    Close,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    Active,
    Pending,
    Closed,
}

fn apply(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::New, Event::Open) => Status::Active,
        (Status::Active, Event::Assign) => Status::Active,
        (Status::Active, Event::Block) => Status::Pending,
        (Status::Pending, Event::Unblock) => Status::Active,
        (Status::Pending, Event::Close) => Status::Pending,
        (Status::Active, Event::Close) => Status::Active,
        (s, _) => s,
    }
}

fn run(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = apply(status, match event {
            Event::Open => Event::Open,
            Event::Assign => Event::Assign,
            Event::Block => Event::Block,
            Event::Unblock => Event::Unblock,
            Event::Close => Event::Close,
        });
    }
    status
}

fn label(status: Status) -> &'static str {
    match status {
        Status::New => "New",
        Status::Active => "Active",
        Status::Pending => "Pending",
        Status::Closed => "Closed",
    }
}

fn main() {
    let a = [Event::Open, Event::Assign, Event::Close];
    let b = [Event::Open, Event::Block, Event::Close];

    println!("A: {}", label(run(&a)));
    println!("B: {}", label(run(&b)));
}

fn collect_tags(lines: &[&str]) -> Vec<String> {
    lines
        .iter()
        .filter_map(|line| line.split_once(':').map(|(_, rest)| rest))
        .flat_map(|rest| rest.split(','))
        .map(|part| part.trim())
        .filter(|part| !part.is_empty())
        .filter(|part| !part.starts_with("skip-"))
        .map(|part| part.to_string())
        .collect()
}

fn summarize(tags: &[String]) -> String {
    let mut counts: Vec<(String, usize)> = Vec::new();

