fn validate(line: &str) -> &'static str {
    let parts: Vec<&str> = line.split(',').collect();
    if parts.len() < 3 {
        return "bad field count";
    }

    let sku = parts[0];
    if sku.len() != 3 || !sku.chars().all(|c| c.is_ascii_alphanumeric()) {
        return "bad sku";
    }

    if parts[1].parse::<u32>().is_err() {
        return "bad qty";
    }

    if parts[2] != "Y" && parts[2] != "N" {
        return "bad active";
    }

    "ok"
}

