fn parse_line(line: &str) -> Result<(), String> {
    let mut id = "";
    let mut name = "";
    let mut age = "";
    let mut active = "";

    for part in line.split(';') {
        let mut it = part.splitn(2, '=');
        let key = it.next().unwrap_or("");
        let value = it.next().unwrap_or("");
        match key {
            "id" => id = value,
            "name" => name = value,
            "age" => age = value,
            "active" => active = value,
            _ => {}
        }
    }

    if id.is_empty() || !id.chars().all(|c| c.is_ascii_digit()) {
        return Err("invalid id".to_string());
    }
    if name.is_empty() {
        return Err("missing name".to_string());
    }
    if !age.is_empty() && age.parse::<u8>().is_err() {
        return Err("invalid age".to_string());
    }
    if active != "true" && active != "false" {
        return Err("invalid active".to_string());
    }

    Ok(())
}

fn main() {
    let input = "id=100;name=Ana;age=29;active=true\nid=101;name=Bob;age=x;active=false\nid=102;age=41;active=true\nid=103;name=Dee;age=22\nid=104;name=Eli;age=20;active=yes\nid=x5;name=Fox;age=33;active=false\nid=106;name=Gia;active=false";

    let mut out = Vec::new();
    let mut ok = 0;

    for (idx, line) in input.lines().enumerate() {
        match parse_line(line) {
            Ok(()) => ok += 1,
            Err(msg) => out.push(format!("err line {}: {}", idx + 1, msg)),
        }
    }

    println!("ok: {}", ok);
    for line in out {
        println!("{}", line);
    }
}

